/**
 * مرکز اهدا پلاسما نوین پلاسما پورا دارو — سرور کامل، تک‌فایلی
 * همه‌چیز (بک‌اند + فرانت‌اند) داخل همین یک فایله؛ فقط با package.json کنارش نیاز داره.
 */
require("dotenv").config();
const path = require("path");
const fs = require("fs");
const express = require("express");
const helmet = require("helmet");
const cookieParser = require("cookie-parser");
const rateLimit = require("express-rate-limit");
const bcrypt = require("bcryptjs");
const jwt = require("jsonwebtoken");

/* ============================================================
   بخش ۱: تنظیمات و ذخیره‌سازی (فایل JSON ساده، بدون دیتابیس جدا)
   ============================================================ */
const DATA_DIR = path.join(__dirname, "data");
const DB_FILE = path.join(DATA_DIR, "db.json");

function defaultData() {
  return {
    settings: {
      centerName: "مرکز اهدا پلاسما نوین پلاسما پورا دارو",
      minGapHours: 240, rescreenMonths: 6, labWaitMinDays: 7, labWaitMaxDays: 10,
      closedWeekdays: [4, 5],
    },
    staff: [], donors: [], messages: [],
    nextIds: { staff: 1, donor: 1, message: 1, visit: 1 },
  };
}
function ensureDb() {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
  if (!fs.existsSync(DB_FILE)) fs.writeFileSync(DB_FILE, JSON.stringify(defaultData(), null, 2), "utf8");
}
function readDb() { ensureDb(); return JSON.parse(fs.readFileSync(DB_FILE, "utf8")); }
function writeDb(data) {
  const tmp = DB_FILE + ".tmp";
  fs.writeFileSync(tmp, JSON.stringify(data, null, 2), "utf8");
  fs.renameSync(tmp, DB_FILE);
}
function mutate(fn) { const db = readDb(); const result = fn(db); writeDb(db); return result; }

/* ============================================================
   بخش ۲: منطق اهلیت اهدا / تعطیلی / اعتبار نمونه
   ============================================================ */
function effectiveGapHours(d, s) { return (d.overrides && d.overrides.minGapHours) || s.minGapHours; }
function effectiveRescreenMonths(d, s) { return (d.overrides && d.overrides.rescreenMonths) || s.rescreenMonths; }
function isClosedDay(date, s) { return s.closedWeekdays.includes(new Date(date).getDay()); }
function nextOpenDate(date, s) { const d = new Date(date); while (isClosedDay(d, s)) d.setDate(d.getDate() + 1); return d; }
function donationVisits(d) { return d.visits.filter((v) => v.type === "donation").sort((a, b) => new Date(b.date) - new Date(a.date)); }
function screeningVisits(d) { return d.visits.filter((v) => v.type === "screening").sort((a, b) => new Date(b.date) - new Date(a.date)); }
function lastDonation(d) { return donationVisits(d)[0] || null; }
function lastScreening(d) { return screeningVisits(d)[0] || null; }
function monthsBetween(a, b) { const d1 = new Date(a), d2 = new Date(b); return (d2.getFullYear() - d1.getFullYear()) * 12 + (d2.getMonth() - d1.getMonth()); }
function isScreeningValid(d, s, now = new Date()) { const last = lastScreening(d); if (!last) return false; return monthsBetween(last.date, now) < effectiveRescreenMonths(d, s); }
function nextEligibleDate(d, s, now = new Date()) {
  const last = lastDonation(d);
  let base = null;
  if (last) base = new Date(new Date(last.date).getTime() + effectiveGapHours(d, s) * 3600 * 1000);
  if (!base) return isClosedDay(now, s) ? nextOpenDate(now, s) : null;
  return nextOpenDate(base, s);
}
function isEligibleNow(d, s, now = new Date()) {
  if (d.status !== "approved") return false;
  if (!isScreeningValid(d, s, now)) return false;
  const next = nextEligibleDate(d, s, now);
  return !next || next <= now;
}
function pendingFollowUp(d, now = new Date()) {
  const last = lastDonation(d);
  if (!last || last.followUp) return null;
  return (now - new Date(last.date)) / 3600000 >= 20 ? last : null;
}
function donorFlagged(d) { return d.visits.some((v) => (v.immediateCheck && v.immediateCheck.concerning) || (v.followUp && v.followUp.concerning)); }
function normalizePhone(p) { return String(p || "").replace(/[^0-9]/g, ""); }

/* ============================================================
   بخش ۳: احراز هویت کارکنان (JWT در کوکی httpOnly)
   ============================================================ */
const JWT_SECRET = process.env.JWT_SECRET || "insecure-dev-secret-change-me";
if (JWT_SECRET === "insecure-dev-secret-change-me") {
  console.warn("⚠️  JWT_SECRET در .env تنظیم نشده. یک رشته‌ی تصادفی و محرمانه ست کنید.");
}
function signToken(staff) {
  return jwt.sign({ id: staff.id, username: staff.username, role: staff.role }, JWT_SECRET, { expiresIn: "12h" });
}
function requireAuth(req, res, next) {
  const token = req.cookies && req.cookies.staff_token;
  if (!token) return res.status(401).json({ error: "لازمه وارد بشید" });
  try { req.staff = jwt.verify(token, JWT_SECRET); next(); }
  catch (e) { return res.status(401).json({ error: "نشست شما منقضی شده، دوباره وارد بشید" }); }
}
function requireAdmin(req, res, next) {
  if (!req.staff || req.staff.role !== "admin") return res.status(403).json({ error: "فقط مدیر به این بخش دسترسی داره" });
  next();
}

/* ============================================================
   بخش ۴: اپ Express و میان‌افزارهای امنیتی
   ============================================================ */
const app = express();
const PORT = process.env.PORT || 3000;
const isProd = process.env.NODE_ENV === "production";

app.set("trust proxy", 1);
app.use(helmet({ contentSecurityPolicy: {
  directives: {
    defaultSrc: ["'self'"],
    styleSrc: ["'self'", "'unsafe-inline'", "https://cdn.tailwindcss.com"],
    scriptSrc: ["'self'", "'unsafe-inline'", "https://cdn.tailwindcss.com"],
    imgSrc: ["'self'", "data:"],
    connectSrc: ["'self'"],
  },
}}));
app.use(express.json({ limit: "200kb" }));
app.use(cookieParser());

const loginLimiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 20 });
app.use("/api/auth/login", loginLimiter);
const publicLimiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 300 });
app.use("/api/donors", publicLimiter);

const cookieOpts = { httpOnly: true, sameSite: "lax", secure: isProd, maxAge: 12 * 60 * 60 * 1000 };

/* ============================================================
   بخش ۵: مسیرهای احراز هویت کارکنان
   ============================================================ */
app.post("/api/auth/login", (req, res) => {
  const { username, password } = req.body || {};
  if (!username || !password) return res.status(400).json({ error: "نام کاربری و رمز عبور لازمه" });
  const db = readDb();
  const staff = db.staff.find((s) => s.username === username);
  if (!staff || !bcrypt.compareSync(password, staff.passwordHash)) return res.status(401).json({ error: "نام کاربری یا رمز عبور اشتباهه" });
  res.cookie("staff_token", signToken(staff), cookieOpts);
  res.json({ id: staff.id, username: staff.username, role: staff.role, mustChangePassword: !!staff.mustChangePassword });
});

app.post("/api/auth/logout", (req, res) => { res.clearCookie("staff_token"); res.json({ ok: true }); });

app.get("/api/auth/me", requireAuth, (req, res) => {
  const db = readDb();
  const staff = db.staff.find((s) => s.id === req.staff.id);
  if (!staff) return res.status(401).json({ error: "کاربر یافت نشد" });
  res.json({ id: staff.id, username: staff.username, role: staff.role, mustChangePassword: !!staff.mustChangePassword });
});

app.post("/api/auth/change-password", requireAuth, (req, res) => {
  const { currentPassword, newPassword } = req.body || {};
  if (!newPassword || newPassword.length < 6) return res.status(400).json({ error: "رمز جدید باید حداقل ۶ کاراکتر باشه" });
  const result = mutate((db) => {
    const staff = db.staff.find((s) => s.id === req.staff.id);
    if (!staff) return { error: "کاربر یافت نشد" };
    if (!bcrypt.compareSync(currentPassword || "", staff.passwordHash)) return { error: "رمز فعلی اشتباهه" };
    staff.passwordHash = bcrypt.hashSync(newPassword, 12);
    staff.mustChangePassword = false;
    return { ok: true };
  });
  if (result.error) return res.status(400).json(result);
  res.json(result);
});

/* ============================================================
   بخش ۶: مسیرهای عمومی اهداکننده
   ============================================================ */
function donorPublicView(d, settings) {
  const now = new Date();
  return {
    phone: d.phone, name: d.name, status: d.status, screeningDate: d.screeningDate || null,
    createdAt: d.createdAt, visits: d.visits,
    eligibleNow: isEligibleNow(d, settings, now),
    nextEligibleDate: nextEligibleDate(d, settings, now),
    screeningValid: isScreeningValid(d, settings, now),
    pendingFollowUp: pendingFollowUp(d, now),
    needsRescreen: d.status === "approved" && !isScreeningValid(d, settings, now),
  };
}

app.get("/api/donors/settings/public", (req, res) => {
  const s = readDb().settings;
  res.json({ centerName: s.centerName, minGapHours: s.minGapHours, rescreenMonths: s.rescreenMonths, labWaitMinDays: s.labWaitMinDays, labWaitMaxDays: s.labWaitMaxDays, closedWeekdays: s.closedWeekdays });
});

app.post("/api/donors/register", (req, res) => {
  const phone = normalizePhone(req.body && req.body.phone);
  const name = String((req.body && req.body.name) || "").trim();
  if (phone.length < 10) return res.status(400).json({ error: "شماره موبایل معتبر نیست" });
  if (name.length < 2) return res.status(400).json({ error: "نام معتبر نیست" });
  const result = mutate((db) => {
    if (db.donors.find((d) => d.phone === phone)) return { error: "این شماره قبلاً ثبت شده — از همون شماره وارد بشید" };
    const donor = { id: db.nextIds.donor++, phone, name, status: "new", screeningDate: null, overrides: {}, visits: [], createdAt: new Date().toISOString() };
    db.donors.push(donor);
    return { donor };
  });
  if (result.error) return res.status(409).json(result);
  res.status(201).json(donorPublicView(result.donor, readDb().settings));
});

app.get("/api/donors/:phone", (req, res) => {
  const db = readDb();
  const donor = db.donors.find((d) => d.phone === normalizePhone(req.params.phone));
  if (!donor) return res.status(404).json({ error: "پرونده‌ای با این شماره پیدا نشد" });
  res.json(donorPublicView(donor, db.settings));
});

app.get("/api/donors/:phone/messages", (req, res) => {
  const db = readDb();
  const donor = db.donors.find((d) => d.phone === normalizePhone(req.params.phone));
  if (!donor) return res.status(404).json({ error: "پرونده‌ای با این شماره پیدا نشد" });
  res.json(db.messages.filter((m) => m.donorId === donor.id).sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt)));
});

app.post("/api/donors/:phone/visits", (req, res) => {
  const phone = normalizePhone(req.params.phone);
  const type = req.body && req.body.type;
  if (!["screening", "donation"].includes(type)) return res.status(400).json({ error: "نوع ویزیت نامعتبره" });
  const result = mutate((db) => {
    const donor = db.donors.find((d) => d.phone === phone);
    if (!donor) return { error: "پرونده پیدا نشد" };
    const hasScreening = donor.visits.some((v) => v.type === "screening");
    if (!hasScreening && type !== "screening") return { error: "اول باید ویزیت غربالگری ثبت بشه" };
    if (type === "donation" && !isEligibleNow(donor, db.settings)) return { error: "در حال حاضر مجاز به ثبت اهدا نیستید" };
    const visit = { id: db.nextIds.visit++, type, date: new Date().toISOString(), survey: null, immediateCheck: type === "donation" ? null : undefined, followUp: null };
    donor.visits.unshift(visit);
    return { donor, visit };
  });
  if (result.error) return res.status(400).json(result);
  res.status(201).json({ visit: result.visit, donor: donorPublicView(result.donor, readDb().settings) });
});

app.post("/api/donors/:phone/visits/:visitId/survey", (req, res) => {
  const phone = normalizePhone(req.params.phone);
  const visitId = Number(req.params.visitId);
  const result = mutate((db) => {
    const donor = db.donors.find((d) => d.phone === phone);
    if (!donor) return { error: "پرونده پیدا نشد" };
    const visit = donor.visits.find((v) => v.id === visitId);
    if (!visit) return { error: "ویزیت پیدا نشد" };
    visit.survey = { ...req.body, completedAt: new Date().toISOString() };
    if (visit.type === "screening" && (donor.status === "new" || donor.status === "approved")) {
      donor.status = "awaiting_approval";
      donor.screeningDate = visit.date;
    }
    return { donor, visit };
  });
  if (result.error) return res.status(400).json(result);
  res.json({ visit: result.visit, donor: donorPublicView(result.donor, readDb().settings) });
});

app.post("/api/donors/:phone/visits/:visitId/immediate-check", (req, res) => {
  const phone = normalizePhone(req.params.phone);
  const visitId = Number(req.params.visitId);
  const { symptoms, feeling } = req.body || {};
  if (!Array.isArray(symptoms) || !feeling) return res.status(400).json({ error: "پاسخ‌ها ناقصه" });
  const concerning = symptoms.some((s) => s !== "هیچ‌کدام") || feeling === "ضعیف";
  const result = mutate((db) => {
    const donor = db.donors.find((d) => d.phone === phone);
    if (!donor) return { error: "پرونده پیدا نشد" };
    const visit = donor.visits.find((v) => v.id === visitId);
    if (!visit) return { error: "ویزیت پیدا نشد" };
    visit.immediateCheck = { symptoms, feeling, concerning, completedAt: new Date().toISOString() };
    return { donor, visit };
  });
  if (result.error) return res.status(400).json(result);
  res.json({ visit: result.visit, donor: donorPublicView(result.donor, readDb().settings) });
});

app.post("/api/donors/:phone/visits/:visitId/follow-up", (req, res) => {
  const phone = normalizePhone(req.params.phone);
  const visitId = Number(req.params.visitId);
  const { symptoms, feeling } = req.body || {};
  if (!Array.isArray(symptoms) || !feeling) return res.status(400).json({ error: "پاسخ‌ها ناقصه" });
  const concerning = symptoms.some((s) => s !== "هیچ‌کدام") || feeling === "ضعیف";
  const result = mutate((db) => {
    const donor = db.donors.find((d) => d.phone === phone);
    if (!donor) return { error: "پرونده پیدا نشد" };
    const visit = donor.visits.find((v) => v.id === visitId);
    if (!visit) return { error: "ویزیت پیدا نشد" };
    visit.followUp = { symptoms, feeling, concerning, completedAt: new Date().toISOString() };
    return { donor, visit };
  });
  if (result.error) return res.status(400).json(result);
  res.json({ visit: result.visit, donor: donorPublicView(result.donor, readDb().settings) });
});

/* ============================================================
   بخش ۷: مسیرهای کارکنان/مدیریت
   ============================================================ */
function donorAdminView(d, settings) {
  const now = new Date();
  return { ...d, eligibleNow: isEligibleNow(d, settings, now), nextEligibleDate: nextEligibleDate(d, settings, now),
    screeningValid: isScreeningValid(d, settings, now), pendingFollowUp: pendingFollowUp(d, now), flagged: donorFlagged(d) };
}

const adminRouter = express.Router();
adminRouter.use(requireAuth);

adminRouter.get("/settings", (req, res) => res.json(readDb().settings));

adminRouter.put("/settings", requireAdmin, (req, res) => {
  const { minGapHours, rescreenMonths, labWaitMinDays, labWaitMaxDays, closedWeekdays, centerName } = req.body || {};
  const result = mutate((db) => {
    if (minGapHours) db.settings.minGapHours = Number(minGapHours);
    if (rescreenMonths) db.settings.rescreenMonths = Number(rescreenMonths);
    if (labWaitMinDays) db.settings.labWaitMinDays = Number(labWaitMinDays);
    if (labWaitMaxDays) db.settings.labWaitMaxDays = Number(labWaitMaxDays);
    if (Array.isArray(closedWeekdays)) db.settings.closedWeekdays = closedWeekdays.map(Number);
    if (centerName) db.settings.centerName = String(centerName);
    return db.settings;
  });
  res.json(result);
});

adminRouter.get("/donors", (req, res) => { const db = readDb(); res.json(db.donors.map((d) => donorAdminView(d, db.settings))); });

adminRouter.get("/donors/:phone", (req, res) => {
  const db = readDb();
  const donor = db.donors.find((d) => d.phone === req.params.phone);
  if (!donor) return res.status(404).json({ error: "پیدا نشد" });
  res.json(donorAdminView(donor, db.settings));
});

adminRouter.post("/donors/:phone/approve", (req, res) => {
  const result = mutate((db) => {
    const donor = db.donors.find((d) => d.phone === req.params.phone);
    if (!donor) return { error: "پیدا نشد" };
    donor.status = "approved";
    return { donor };
  });
  if (result.error) return res.status(404).json(result);
  res.json(donorAdminView(result.donor, readDb().settings));
});

adminRouter.put("/donors/:phone/overrides", requireAdmin, (req, res) => {
  const { minGapHours, rescreenMonths } = req.body || {};
  const result = mutate((db) => {
    const donor = db.donors.find((d) => d.phone === req.params.phone);
    if (!donor) return { error: "پیدا نشد" };
    donor.overrides = { minGapHours: minGapHours ? Number(minGapHours) : null, rescreenMonths: rescreenMonths ? Number(rescreenMonths) : null };
    return { donor };
  });
  if (result.error) return res.status(404).json(result);
  res.json(donorAdminView(result.donor, readDb().settings));
});

adminRouter.post("/donors/:phone/messages", (req, res) => {
  const { body, appointmentDate } = req.body || {};
  if (!body || !body.trim()) return res.status(400).json({ error: "متن پیام خالیه" });
  const result = mutate((db) => {
    const donor = db.donors.find((d) => d.phone === req.params.phone);
    if (!donor) return { error: "پیدا نشد" };
    const message = { id: db.nextIds.message++, donorId: donor.id, body: body.trim(), appointmentDate: appointmentDate || null, createdByUsername: req.staff.username, createdAt: new Date().toISOString() };
    db.messages.push(message);
    return { message };
  });
  if (result.error) return res.status(404).json(result);
  res.status(201).json(result.message);
});

adminRouter.get("/donors/:phone/messages", (req, res) => {
  const db = readDb();
  const donor = db.donors.find((d) => d.phone === req.params.phone);
  if (!donor) return res.status(404).json({ error: "پیدا نشد" });
  res.json(db.messages.filter((m) => m.donorId === donor.id).sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt)));
});

adminRouter.get("/staff", requireAdmin, (req, res) => {
  res.json(readDb().staff.map((s) => ({ id: s.id, username: s.username, role: s.role, createdAt: s.createdAt })));
});

adminRouter.post("/staff", requireAdmin, (req, res) => {
  const { username, password, role } = req.body || {};
  if (!username || !password || password.length < 6) return res.status(400).json({ error: "نام کاربری لازمه و رمز باید حداقل ۶ کاراکتر باشه" });
  const result = mutate((db) => {
    if (db.staff.find((s) => s.username === username)) return { error: "این نام کاربری قبلاً وجود داره" };
    const staff = { id: db.nextIds.staff++, username, passwordHash: bcrypt.hashSync(password, 12), role: role === "admin" ? "admin" : "staff", mustChangePassword: true, createdAt: new Date().toISOString() };
    db.staff.push(staff);
    return { staff };
  });
  if (result.error) return res.status(409).json(result);
  res.status(201).json({ id: result.staff.id, username: result.staff.username, role: result.staff.role });
});

adminRouter.delete("/staff/:id", requireAdmin, (req, res) => {
  const id = Number(req.params.id);
  if (id === req.staff.id) return res.status(400).json({ error: "نمی‌تونید حساب خودتون رو حذف کنید" });
  const result = mutate((db) => {
    const before = db.staff.length;
    db.staff = db.staff.filter((s) => s.id !== id);
    if (db.staff.length === before) return { error: "پیدا نشد" };
    return { ok: true };
  });
  if (result.error) return res.status(404).json(result);
  res.json(result);
});

app.use("/api/admin", adminRouter);

/* ============================================================
   بخش ۸: فرانت‌اند (HTML + JS داخل همین فایل، به‌صورت base64)
   ============================================================ */
const INDEX_HTML = Buffer.from("", "base64").toString("utf8");
const APP_JS = Buffer.from("", "base64").toString("utf8");

app.get("/app.js", (req, res) => { res.type("application/javascript").send(APP_JS); });
app.get("/", (req, res) => { res.type("html").send(INDEX_HTML); });
app.get("*", (req, res) => { res.type("html").send(INDEX_HTML); });

/* ============================================================
   بخش ۹: ساخت خودکار حساب مدیر در اولین اجرا
   ============================================================ */
function bootstrapAdmin() {
  const username = process.env.ADMIN_USERNAME;
  const password = process.env.ADMIN_PASSWORD;
  mutate((db) => {
    if (db.staff.length > 0) return;
    if (!username || !password) {
      console.warn("⚠️  ADMIN_USERNAME / ADMIN_PASSWORD در .env تنظیم نشده — هیچ حساب مدیری ساخته نشد.");
      return;
    }
    db.staff.push({ id: db.nextIds.staff++, username, passwordHash: bcrypt.hashSync(password, 12), role: "admin", mustChangePassword: true, createdAt: new Date().toISOString() });
    console.log(`✅ حساب مدیر اولیه ساخته شد (نام کاربری: ${username}). بعد از ورود، رمز رو عوض کنید.`);
  });
}
bootstrapAdmin();

app.listen(PORT, () => console.log(`🩸 سرور مرکز اهدا پلاسما روی پورت ${PORT} در حال اجراست`));
